import React from 'react';
import { NavLink } from 'react-router-dom';

const Sidebar = () => {
  const navItems = [
    { path: '/', label: 'Dashboard', icon: '📊' },
    { path: '/staff', label: 'Manage Staff', icon: '🛡️' },
    { path: '/members', label: 'Manage Members', icon: '👥' },
    { path: '/loans', label: 'Loan Approvals', icon: '💸' },
    { path: '/reports', label: 'Reports', icon: '📑' },
    { path: '/audit-logs', label: 'Audit Logs', icon: '📜' },
  ];

  return (
    <aside className="sidebar">
      <div className="sidebar-header">
        <div className="brand-icon">🏦</div>
        <div className="brand-text">
          <h1>Harari Admin</h1>
          <p>Management System</p>
        </div>
      </div>

      <nav className="nav">
        {navItems.map((item) => (
          <NavLink
            key={item.path}
            to={item.path}
            end={item.path === '/'}
            className={({ isActive }) => `nav-link ${isActive ? 'active' : ''}`}
          >
            <span style={{ fontSize: '1.2rem' }}>{item.icon}</span>
            <span>{item.label}</span>
          </NavLink>
        ))}
      </nav>

      <div className="sidebar-footer">
        <div className="user-info">
          <p style={{ fontSize: '0.75rem', color: 'var(--text-secondary)', margin: 0 }}>Logged in as</p>
          <p style={{ fontWeight: 500, margin: 0 }}>Administrator</p>
        </div>
      </div>
    </aside>
  );
};

export default Sidebar;
